import{_ as a,o,c as r,a2 as e}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"西天梵境（大西天）","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/beihai/xitianfanjing.md","filePath":"landmarks/beihai/xitianfanjing.md","lastUpdated":1784720050000}'),n={name:"landmarks/beihai/xitianfanjing.md"};function l(i,t,s,g,d,h){return o(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="西天梵境-大西天" tabindex="-1">西天梵境（大西天） <a class="header-anchor" href="#西天梵境-大西天" aria-label="Permalink to &quot;西天梵境（大西天）&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1758647534123-4a8508237a18?w=1200&amp;q=80" alt="西天梵境"></p><blockquote><p>琉璃牌坊后，一座全由金丝楠木建成的大殿静立了数百年——它是中国现存最大的楠木殿，也是北海北岸最深沉的梵音所在。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p><strong>西天梵境</strong>，又称<strong>大西天</strong>，位于北海北岸，是北海规模最宏大的<strong>藏传佛教建筑群</strong>。它始建于<strong>明万历年间</strong>，清代又经扩建，是帝王礼佛祈福的重要场所。整座建筑群以一条南北轴线层层递进，山门、牌坊、殿宇次第展开，气势庄严而恢宏。</p><p>西天梵境最负盛名的，是其主殿<strong>大慈真如宝殿</strong>——一座<strong>通体以金丝楠木建成</strong>的大殿。它是中国<strong>现存最大的楠木殿</strong>，梁柱、门窗皆用整料金丝楠木，不施彩绘、不加油饰，仅以楠木本色的温润纹理与幽香取胜，历数百年而木色如新，是中国古代木构建筑的绝世珍品。</p><p>西天梵境之名，取自佛教&quot;西方极乐净土&quot;之意。在皇家苑囿的山水之间辟出这样一片庄严梵境，既满足了帝王礼佛祈福的需要，也以&quot;梵境&quot;之名点化了整座园林的精神意境——北海不仅是游赏的乐园，更是安顿心灵的净土。</p><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年代</th><th style="text-align:left;">大事</th></tr></thead><tbody><tr><td style="text-align:left;">明万历年间</td><td style="text-align:left;">始建，为皇家藏传佛教寺院</td></tr><tr><td style="text-align:left;">清乾隆年间</td><td style="text-align:left;">大规模扩建，增建殿宇，成北岸最大梵刹</td></tr><tr><td style="text-align:left;">清代</td><td style="text-align:left;">帝王礼佛祈福的重要场所</td></tr><tr><td style="text-align:left;">当代</td><td style="text-align:left;">列为全国重点文物保护单位，对外开放</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">建筑</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>琉璃牌坊&quot;华藏界&quot;</strong></td><td style="text-align:left;">入口处的彩色琉璃牌坊，题额&quot;华藏界&quot;，华丽庄严</td></tr><tr><td style="text-align:left;"><strong>天王殿</strong></td><td style="text-align:left;">山门后的第一重殿宇，供奉弥勒与四大天王</td></tr><tr><td style="text-align:left;"><strong>大慈真如宝殿</strong></td><td style="text-align:left;">主殿，通体金丝楠木建成，中国现存最大的楠木殿</td></tr><tr><td style="text-align:left;"><strong>琉璃阁</strong></td><td style="text-align:left;">殿后的高阁，以琉璃装饰，为建筑群的高潮</td></tr></tbody></table><p>整座建筑群沿中轴线展开：自入口的<strong>琉璃牌坊&quot;华藏界&quot;<strong>而入，过山门、<strong>天王殿</strong>，便来到全寺的核心——<strong>大慈真如宝殿</strong>。此殿面阔五间，殿身梁柱、藻井、门窗</strong>全部采用金丝楠木</strong>，不施丹彩，仅凭楠木本身的金色丝纹与天然幽香彰显高贵，殿内空间宏敞、木色温润，是中国现存体量最大的楠木殿，堪称国宝级建筑。大殿之后为<strong>琉璃阁</strong>，以琉璃构件装饰，与前面的楠木大殿一素一华，形成强烈的视觉对比，将建筑群推向高潮。</p><p>西天梵境兼具汉藏两种建筑风格，既体现了皇家对藏传佛教的尊崇，也展现了明清官式建筑的最高水准。建筑群依山面水，前临太液池碧波，后倚北岸古木，殿宇在松柏掩映中层层递高，梵音与湖光相和，营造出肃穆而清幽的宗教氛围。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="金丝楠木-比黄金还贵的木头" tabindex="-1">金丝楠木：比黄金还贵的木头 <a class="header-anchor" href="#金丝楠木-比黄金还贵的木头" aria-label="Permalink to &quot;金丝楠木：比黄金还贵的木头&quot;">​</a></h3><p>大慈真如宝殿之所以珍贵，在于它<strong>通体以金丝楠木建成</strong>。金丝楠木生长缓慢、成材需数百年，且多产于川黔深山，自古有&quot;<strong>水不能浸、蚁不能穴</strong>&quot;之说，木性稳定、纹理如金丝、散发幽香，是中国最名贵的建筑用材，明清时期有&quot;<strong>一寸楠木一寸金</strong>&quot;的说法。以整殿梁柱皆用金丝楠木且不加彩绘，这在现存古建中极为罕见。数百年过去，殿内楠木依然温润生香、木色不改，是这座大殿最震撼人心之处。</p><h3 id="为何称-大西天" tabindex="-1">为何称&quot;大西天&quot; <a class="header-anchor" href="#为何称-大西天" aria-label="Permalink to &quot;为何称&quot;大西天&quot;&quot;">​</a></h3><p>北海北岸原有两处佛教建筑群，规模较小的称&quot;小西天&quot;（阐福寺一带），规模宏大的这处则称&quot;<strong>大西天</strong>&quot;，即西天梵境。&quot;西天&quot;本是佛教中极乐世界的代称，帝王以此命名皇家佛寺，既寄托了对净土的向往，也暗含&quot;君权神授、护佑社稷&quot;的政治寓意。清代帝王崇奉藏传佛教，西天梵境正是这一信仰在皇家园林中的庄严呈现。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>金丝楠木大殿</strong>：亲睹中国现存最大的楠木殿，感受整料楠木的金色纹理与天然幽香，这是别处难寻的国宝级建筑。</li><li><strong>不施彩绘的素雅</strong>：与故宫的红墙彩画不同，此殿全凭木质本色取胜，体会&quot;清水出芙蓉&quot;的建筑美学。</li><li><strong>琉璃牌坊&quot;华藏界&quot;</strong>：入口的彩色琉璃牌坊华丽庄严，题额&quot;华藏界&quot;三字点明梵境主题，是拍照的绝佳取景地。</li><li><strong>汉藏合璧</strong>：观察建筑群中汉藏两种风格的交融，体会皇家宗教建筑的独特气质。</li><li><strong>琉璃阁对比</strong>：将素雅的楠木殿与华美的琉璃阁对照欣赏，一素一华，匠心独具。</li></ol><h2 id="拍照机位" tabindex="-1">拍照机位 <a class="header-anchor" href="#拍照机位" aria-label="Permalink to &quot;拍照机位&quot;">​</a></h2><ol><li><strong>琉璃牌坊</strong>：正面拍摄&quot;华藏界&quot;琉璃牌坊，七彩琉璃在顺光下最为鲜艳。</li><li><strong>楠木殿内</strong>：殿内光线柔和，拍摄金丝楠木梁柱的纹理与藻井，质感温润（注意是否允许拍摄）。</li><li><strong>殿宇纵深</strong>：沿中轴线拍摄山门—天王殿—大殿的层层递进，凸显梵刹的庄严纵深。</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li><strong>重点看大殿</strong>：大慈真如宝殿是西天梵境的精华，务必入内（如开放）感受楠木的纹理与香气。</li><li><strong>细闻楠木香</strong>：金丝楠木会散发淡淡幽香，静立殿中细嗅，是别处难得的体验。</li><li><strong>上午光线佳</strong>：琉璃牌坊与大殿在上午顺光时色彩最饱满，适合拍照。</li><li><strong>联游北岸</strong>：西天梵境与<a href="/beijing-travel-guide/landmarks/beihai/jingxinzhai.html">静心斋</a>、<a href="/beijing-travel-guide/landmarks/beihai/jiulongbi.html">九龙壁</a>、<a href="/beijing-travel-guide/landmarks/beihai/wulongting.html">五龙亭</a>同在北海北岸，可沿湖串联游览。</li><li><strong>东岸亦佳</strong>：除北岸外，北海东岸的<strong>濠濮间</strong>、<strong>画舫斋</strong>也是清幽的园中之景，时间充裕可顺路一游。</li><li><strong>静心参观</strong>：既是梵境，参观时宜保持安静，尊重宗教场所的氛围。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：大慈真如宝殿为什么这么珍贵？</strong></p><p>它是中国现存最大的、通体以金丝楠木建成的大殿。金丝楠木极为名贵稀有（&quot;一寸楠木一寸金&quot;），且整座大殿梁柱门窗皆用整料楠木、不施彩绘，全凭木质本色取胜，这在现存古建中几乎独一无二。</p><p><strong>Q：西天梵境为什么又叫&quot;大西天&quot;？</strong></p><p>北海北岸有两处佛教建筑群，较小的称&quot;小西天&quot;，这处规模宏大的称&quot;大西天&quot;，即西天梵境。&quot;西天&quot;是佛教极乐净土的代称，帝王以此命名皇家佛寺，寄托对净土的向往。</p><p><strong>Q：西天梵境和琼华岛白塔都是藏传佛教建筑吗？</strong></p><p>是的，两者都与藏传佛教渊源深厚：琼华岛白塔是藏式喇嘛塔，西天梵境则是藏传佛教寺院建筑群。它们共同体现了清代皇家对藏传佛教的尊崇，是北海宗教文化的双璧。</p><hr><p><strong>📍 位置</strong>：北海北岸，藏传佛教建筑群 <strong>⏱️ 建议游览</strong>：30-40分钟 <strong>🔗 相邻</strong>：<a href="/beijing-travel-guide/landmarks/beihai/jingxinzhai.html">静心斋</a>（北岸相邻） <strong>🔗 相邻</strong>：<a href="/beijing-travel-guide/landmarks/beihai/jiulongbi.html">九龙壁</a>、<a href="/beijing-travel-guide/landmarks/beihai/wulongting.html">五龙亭</a>（北岸向西） <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/beihai/">北海公园概览</a></p>',33)])])}const b=a(n,[["render",l]]);export{q as __pageData,b as default};
